mapper.select:
SELECT COUNT(DISTINCT d.device_id) AS totalDeviceCount, COUNT(DISTINCT CASE WHEN d.status = 'NORMAL' THEN d.device_id END) AS normalDeviceCount, COUNT(DISTINCT CASE WHEN d.status = 'WARNING' THEN d.device_id END) AS warningDeviceCount, COUNT(DISTINCT CASE WHEN d.status = 'ERROR' THEN d.device_id END) AS errorDeviceCount, COUNT(DISTINCT CASE WHEN d.status = 'OFFLINE' THEN d.device_id END) AS offlineDeviceCount,
IFNULL( SUM( CASE WHEN d.status != 'OFFLINE' AND m.solar_generation_kwh BETWEEN 0 AND d.capacity_kw * 24 THEN m.solar_generation_kwh END ), 0 ) AS todayGenerationKwh,
IFNULL( AVG( CASE WHEN d.status != 'OFFLINE' AND m.soc BETWEEN 0 AND 100 THEN m.soc END ), 0 ) AS averageSoc,
IFNULL( SUM( CASE WHEN d.status != 'OFFLINE' AND m.saved_cost >= 0 AND m.solar_generation_kwh BETWEEN 0 AND d.capacity_kw * 24 AND m.saved_cost <= m.solar_generation_kwh * d.electricity_rate THEN m.saved_cost END ), 0 ) AS todaySavedCost
FROM ess_device d LEFT JOIN monitoring m ON d.device_id = m.device_id AND m.record_time >= STR_TO_DATE(#{selectedDate}, '%Y-%m-%d') AND m.record_time < DATE_ADD(STR_TO_DATE(#{selectedDate}, '%Y-%m-%d'), INTERVAL 1 DAY)
WHERE d.member_id = #{memberId}
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}

SELECT
    device_id,
    device_name
FROM ess_device
WHERE member_id = #{memberId}


    AND group_id = #{groupId}
